def browser_cache(max_size, operations):
    policies = {}
    domain_data = {}
    domain_last_access = {}
    key_last_access = {}
    key_frequency = {}
    key_insert_order = {}
    time = [0]
    current_size = [0]

    def get_policy(domain):
        return policies.get(domain, "LRU")

    def evict_one():
        if not domain_last_access:
            return
        lru_domain = min(domain_last_access, key=lambda d: domain_last_access[d])
        policy = get_policy(lru_domain)
        keys = key_last_access[lru_domain]
        if policy == "LRU":
            victim = min(keys, key=lambda k: keys[k])
        elif policy == "LFU":
            freqs = key_frequency[lru_domain]
            victim = min(keys, key=lambda k: (freqs[k], keys[k]))
        elif policy == "FIFO":
            insert_times = key_insert_order[lru_domain]
            victim = min(insert_times, key=lambda k: insert_times[k])
        else:
            victim = min(keys, key=lambda k: keys[k])
        del domain_data[lru_domain][victim]
        del key_last_access[lru_domain][victim]
        del key_frequency[lru_domain][victim]
        del key_insert_order[lru_domain][victim]
        current_size[0] -= 1
        if not domain_data[lru_domain]:
            del domain_data[lru_domain]
            del domain_last_access[lru_domain]
            del key_last_access[lru_domain]
            del key_frequency[lru_domain]
            del key_insert_order[lru_domain]

    def do_set_policy(domain, policy):
        policies[domain] = policy
        return None

    def do_put(domain, key, value):
        time[0] += 1
        t = time[0]
        if domain in domain_data and key in domain_data[domain]:
            domain_data[domain][key] = value
            key_last_access[domain][key] = t
            key_frequency[domain][key] += 1
            domain_last_access[domain] = t
            return None
        if current_size[0] >= max_size:
            evict_one()
        if domain not in domain_data:
            domain_data[domain] = {}
            key_last_access[domain] = {}
            key_frequency[domain] = {}
            key_insert_order[domain] = {}
        domain_data[domain][key] = value
        key_last_access[domain][key] = t
        key_frequency[domain][key] = 1
        key_insert_order[domain][key] = t
        domain_last_access[domain] = t
        current_size[0] += 1
        return None

    def do_get(domain, key):
        time[0] += 1
        t = time[0]
        if domain in domain_data and key in domain_data[domain]:
            key_last_access[domain][key] = t
            key_frequency[domain][key] += 1
            domain_last_access[domain] = t
            return domain_data[domain][key]
        return -1

    def do_get_state():
        result = {}
        for domain in sorted(domain_data):
            result[domain] = {}
            for key in sorted(domain_data[domain]):
                result[domain][key] = domain_data[domain][key]
        return result

    results = []
    for op in operations:
        if op[0] == "set_policy":
            results.append(do_set_policy(op[1], op[2]))
        elif op[0] == "put":
            results.append(do_put(op[1], op[2], op[3]))
        elif op[0] == "get":
            results.append(do_get(op[1], op[2]))
        elif op[0] == "get_state":
            results.append(do_get_state())
    return results
